const body = $input.first().json.body || $input.first().json;
const description = (body.description || '').trim();
const channelId = body.channelId || '';
const userId = body.userId || '';
const userName = body.userName || 'user';

const systemPrompt = `You are an expert OpenSCAD programmer specializing in 3D-printable parametric models.

Output RULES (strictly follow):
1. Output ONLY valid OpenSCAD code — no markdown fences, no explanations, no text before or after
2. Start with variable declarations (dimensions, tolerances)
3. Add brief comments explaining each major section
4. Ensure the model is manifold/watertight for 3D printing
5. Use union(), difference(), intersection() appropriately
6. Include a translate() to center the model at origin`;

return [{ json: { description, channelId, userId, userName, systemPrompt } }];

const ollamaResp = JSON.parse($input.first().json.data || '{}');
const raw = (ollamaResp.message && ollamaResp.message.content) || ollamaResp.response || '';

// Strip markdown fences if Ollama wrapped it anyway
let code = raw.trim();
const fenceMatch = code.match(/```(?:openscad|scad)?\n([\s\S]*?)```/i);
if (fenceMatch) code = fenceMatch[1].trim();

// Pass through context
const prev = $input.first().json;
return [{ json: {
  code,
  description: prev.description || '',
  channelId: prev.channelId || '',
  userId: prev.userId || '',
  userName: prev.userName || 'user',
} }];

const render = $input.first().json;
const prev = $input.all()[0].json;

const code = prev.code || '';
const description = prev.description || '';
const channelId = prev.channelId || '';
const success = render.success || false;
const jobId = render.job_id || 'unknown';
const stlPath = render.stl_path || null;
const pngB64 = render.png_b64 || null;

// Build Slack message blocks
const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: ':triangular_ruler: 3D Model Generated', emoji: true }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Description:* ${description}` }
  },
];

if (stlPath) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `:white_check_mark: *STL file saved to:*\n\`${stlPath}\`` }
  });
}

if (!success) {
  const stlErr = render.stl_error || '';
  const pngErr = render.png_error || '';
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `:warning: Render had issues: ${stlErr || pngErr || 'check openscad-api logs'}` }
  });
}

blocks.push({
  type: 'section',
  text: { type: 'mrkdwn', text: '*OpenSCAD Code:*' }
});

// Slack code blocks max 3000 chars
const codeSnippet = code.length > 2800 ? code.slice(0, 2800) + '\n// ... (truncated)' : code;
blocks.push({
  type: 'section',
  text: { type: 'mrkdwn', text: '```' + codeSnippet + '```' }
});

blocks.push({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: `:file_folder: Job ID: \`${jobId}\` | Open in OpenSCAD to modify` }]
});

return [{ json: {
  channelId,
  pngB64,
  slackPayload: JSON.stringify({ channel: channelId, blocks }),
} }];

const prev = $input.first().json;
const pngB64 = prev.pngB64 || null;

// Build binary item from base64 if we have a PNG
const result = { json: prev };
if (pngB64) {
  result.binary = {
    data: {
      data: pngB64,
      mimeType: 'image/png',
      fileName: '3d-preview.png',
      fileSize: Math.ceil(pngB64.length * 0.75),
    }
  };
}
return [result];

parameters.body:
={{ (() => {
  const prev = $('Format Response').first().json;
  const fileId = JSON.parse($('Get Upload URL').first().json.data).file_id;
  const blocks = [
    { type: 'header', text: { type: 'plain_text', text: ':triangular_ruler: 3D Model Generated', emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*Description:* ' + (prev.description || '') } },
    { type: 'image', image_url: 'https://files.slack.com/files-pri/' + fileId + '/3d-preview.png', alt_text: '3D preview' },
    { type: 'section', text: { type: 'mrkdwn', text: (prev.stlPath ? ':white_check_mark: *STL saved to:* `' + prev.stlPath + '`' : ':warning: STL render failed — see code below') } },
    { type: 'section', text: { type: 'mrkdwn', text: '*OpenSCAD Code:*' } },
    { type: 'section', text: { type: 'mrkdwn', text: '```' + (prev.code || '').slice(0, 2800) + '```' } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: ':file_folder: Open .scad file in OpenSCAD to edit | :printer: Open .stl in your slicer to print' }] }
  ];
  // Also complete the upload so the file is associated with the channel
  return JSON.stringify({
    channel: prev.channelId,
    blocks,
    unfurl_links: false
  });
})() }}
